    82→### 1.1 Create memory-loader.ts
    83→
    84→**File**: `src/lib/conversation/memory-loader.ts`
    85→
    86→```typescript
    87→import { prisma } from '@/lib/db';
    88→
    89→export interface ConversationMemory {
    90→  recentSummary: string | null;
    91→  keyFacts: string[];
    92→  topics: string[];
    93→  lastSessionDate: Date | null;
    94→}
    95→
    96→/**
    97→ * Load conversation memory for a user-maestro pair.
    98→ * Returns summaries, key facts, and topics from last 3 conversations.
    99→ */
   100→export async function loadConversationMemory(
   101→  userId: string,
   102→  maestroId: string
   103→): Promise<ConversationMemory> {
   104→  const conversations = await prisma.conversation.findMany({
   105→    where: {
   106→      userId,
   107→      characterId: maestroId,
   108→      isActive: false,
   109→      summary: { not: null },
   110→    },
   111→    orderBy: { updatedAt: 'desc' },
   112→    take: 3,
   113→    select: {
   114→      summary: true,
   115→      keyFacts: true,
   116→      topics: true,
   117→      updatedAt: true,
   118→    },
   119→  });
   120→
   121→  if (conversations.length === 0) {
   122→    return {
   123→      recentSummary: null,
   124→      keyFacts: [],
   125→      topics: [],
   126→      lastSessionDate: null,
   127→    };
   128→  }
   129→
   130→  // Merge key facts from all conversations (deduplicated)
   131→  const allKeyFacts = conversations
   132→    .flatMap((c) => {
   133→      try {
   134→        return JSON.parse(c.keyFacts || '[]');
   135→      } catch {
   136→        return [];
   137→      }
   138→    })
   139→    .slice(0, 5); // Max 5 key facts
   140→
   141→  // Merge topics from all conversations (deduplicated)
   142→  const allTopics = [...new Set(
   143→    conversations.flatMap((c) => {
   144→      try {
   145→        return JSON.parse(c.topics || '[]');
   146→      } catch {
   147→        return [];
   148→      }
   149→    })
   150→  )].slice(0, 10); // Max 10 topics
   151→
   152→  return {
   153→    recentSummary: conversations[0].summary,
   154→    keyFacts: allKeyFacts,
   155→    topics: allTopics,
   156→    lastSessionDate: conversations[0].updatedAt,
   157→  };
   158→}
   159→```
