   280→
   281→  it('deduplicates topics across conversations', async () => {
   282→    vi.mocked(prisma.conversation.findMany).mockResolvedValue([
   283→      { summary: 'S1', keyFacts: '[]', topics: '["frazioni", "algebra"]', updatedAt: new Date() },
   284→      { summary: 'S2', keyFacts: '[]', topics: '["frazioni", "geometria"]', updatedAt: new Date() },
   285→    ]);
   286→
   287→    const memory = await loadConversationMemory('user-1', 'melissa');
   288→
   289→    const frazioniCount = memory.topics.filter((t) => t === 'frazioni').length;
   290→    expect(frazioniCount).toBe(1);
   291→  });
   292→
   293→  it('handles malformed JSON gracefully', async () => {
   294→    vi.mocked(prisma.conversation.findMany).mockResolvedValue([
   295→      { summary: 'S1', keyFacts: 'invalid json', topics: '["ok"]', updatedAt: new Date() },
