   396→### 2.1 API endpoint for conversation memory
   397→
   398→**File**: `src/app/api/conversations/memory/route.ts`
   399→
   400→```typescript
   401→import { NextRequest, NextResponse } from 'next/server';
   402→import { cookies } from 'next/headers';
   403→import { loadConversationMemory } from '@/lib/conversation/memory-loader';
   404→
   405→export async function GET(request: NextRequest) {
   406→  const cookieStore = await cookies();
   407→  const userId = cookieStore.get('convergio-user-id')?.value;
   408→
   409→  if (!userId) {
   410→    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
   411→  }
   412→
   413→  const { searchParams } = new URL(request.url);
   414→  const maestroId = searchParams.get('maestroId');
   415→
   416→  if (!maestroId) {
   417→    return NextResponse.json({ error: 'maestroId required' }, { status: 400 });
   418→  }
   419→
   420→  const memory = await loadConversationMemory(userId, maestroId);
   421→
   422→  return NextResponse.json(memory);
   423→}
   424→```
