   161→### 1.2 Create prompt-enhancer.ts
   162→
   163→**File**: `src/lib/conversation/prompt-enhancer.ts`
   164→
   165→```typescript
   166→import { ConversationMemory } from './memory-loader';
   167→import { formatDistanceToNow } from 'date-fns';
   168→import { it } from 'date-fns/locale';
   169→
   170→/**
   171→ * Enhance a Maestro's system prompt with conversation memory.
   172→ * Returns the enhanced prompt, or the original if no memory exists.
   173→ */
   174→export function enhanceSystemPromptWithMemory(
   175→  basePrompt: string,
   176→  memory: ConversationMemory
   177→): string {
   178→  if (!memory.recentSummary) {
   179→    return basePrompt;
   180→  }
   181→
   182→  const timeAgo = memory.lastSessionDate
   183→    ? formatDistanceToNow(memory.lastSessionDate, { addSuffix: true, locale: it })
   184→    : 'tempo fa';
   185→
   186→  const memorySection = `
   187→
   188→## Memoria delle Sessioni Precedenti
   189→
   190→### Ultimo Incontro (${timeAgo})
   191→${memory.recentSummary}
   192→
   193→${memory.keyFacts.length > 0 ? `### Fatti Chiave dello Studente
   194→${memory.keyFacts.map((f) => `- ${f}`).join('\n')}` : ''}
   195→
   196→${memory.topics.length > 0 ? `### Argomenti Gi Trattati
   197→${memory.topics.join(', ')}` : ''}
   198→
   199→---
   200→**ISTRUZIONI MEMORIA**: Usa queste informazioni per personalizzare l'interazione. Fai riferimento naturalmente alle conversazioni passate quando rilevante. Non ripetere concetti gi acquisiti dallo studente. Se lo studente chiede "ti ricordi...?", rispondi facendo riferimento alle informazioni sopra.
   201→`;
   202→
   203→  return basePrompt + memorySection;
   204→}
   205→```
