    } else {
      responseContent = 'Sto elaborando la tua richiesta...';
    }
  }

  return NextResponse.json({
    content: responseContent,  // <-- Now always has value
    toolCalls: toolResults,
    provider: providerConfig.name,
    model: providerConfig.model,
  });
}
